import "./Home.css"
import React, { useState, useEffect } from 'react';
import EditIcon from '@mui/icons-material/Edit';

function Home() {
    const [datos, setDatos] = useState([]);
    const [tipoAnimales, setTipoAnimales] = useState('lecheria');
    const [editItem, setEditItem] = useState(null);

    useEffect(() => {
        const fetchData = async () => {
            try {
                let url;
                if (tipoAnimales === 'corrales') {
                    url = 'http://127.0.0.1:8000/corrales';
                } else if (tipoAnimales === 'personas') {
                    url = 'http://127.0.0.1:8000/personas';
                } else {
                    url = `http://127.0.0.1:8000/animales/${tipoAnimales}`;
                }

                const response = await fetch(url);
                const data = await response.json();
                setDatos(data);
            } catch (error) {
                console.error('Error al obtener datos de la API', error);
            }
        };

        fetchData();
    }, [tipoAnimales]);

    const handleTipoAnimalesChange = (tipo) => {
        setTipoAnimales(tipo);
        setEditItem(null); // Restablecer el elemento de edición al cambiar el tipo de animales
    };

    const formatFieldName = (fieldName) => {
        return fieldName.charAt(0).toUpperCase() + fieldName.slice(1);
    };

    const handleEditClick = (item) => {
        setEditItem(item);
    };

    const handleCancelEdit = () => {
        setEditItem(null);
    };

    const handleSaveEdit = async (editedData) => {
        // Lógica para guardar la edición (enviar a la API, etc.)
        // Puedes implementar esta parte según tus necesidades
        console.log('Guardando edición:', editedData);

        // Después de guardar, restablece el estado de edición
        setEditItem(null);
    };

    return (
        <div className="contenedor">
            {/* ... (código existente) */}
            <div className='contenedor_tabla'>
                <table>
                    <thead>
                        {/* ... (código existente) */}
                    </thead>
                    <tbody>
                        {datos && datos.map((fila, index) => (
                            <tr key={tipoAnimales === 'corrales' || tipoAnimales === 'personas' ? fila.id : index}>
                                {/* ... (código existente) */}
                                <td>
                                    <div className="icono-edicion" onClick={() => handleEditClick(fila)}>
                                        <EditIcon />
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            {editItem && (
                <div className="formulario-edicion">
                    <h2>Editar Registro</h2>
                    {/* Renderiza el formulario de edición con campos prellenados */}
                    <form>
                        {/* ... (renderiza los campos de edición, puedes usar los mismos campos que se muestran en la tabla) */}
                        <button type="button" onClick={handleCancelEdit}>Cancelar</button>
                        <button type="button" onClick={() => handleSaveEdit(editItem)}>Guardar</button>
                    </form>
                </div>
            )}
            <button className="boton-agregar">Agregar</button>
            {/* ... (código existente) */}
        </div>
    );
}

export default Home;
